import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_packages(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for p in fw.get('topLevelPackages', []):
                pkgs[p['id']] = p['resolvedVersion']
        result[name] = pkgs
    return result

b = get_packages(baseline)
a = get_packages(after)

print('=== CHANGES ===')
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg, '-')
        av = ap.get(pkg, '-')
        if bv != av:
            print(f'  {proj}: {pkg} {bv} -> {av}')
            changes = True
if not changes:
    print('  (none)')

print()
print('=== UNCHANGED ===')
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg, '-')
        av = ap.get(pkg, '-')
        if bv == av:
            print(f'  {proj}: {pkg} {av}')
